const currentYear = new Date().getFullYear();
const lookbackYears = 12;
const startYear = currentYear - lookbackYears + 1;
return Array.from({ length: lookbackYears }, (_, index) => ({
  json: {
    market_year: startYear + index
  }
}));

function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
const now = new Date().toISOString();
const _collectedPeriod = getCollectedPeriod(now, 'weekly');
const currentYear = new Date().getFullYear();
const lookbackYears = 6;
const startYear = currentYear - lookbackYears + 1;
// USDA PSD unit = 1.000 sacchi 60-kg = 60 MT ciascuno
const BAG_TO_MT = 60;
const ATTRIBUTE_MAP = {
  20: 'Beginning Stocks',
  28: 'Production',
  29: 'Arabica Production',
  53: 'Robusta Production',
  56: 'Other Production',
  57: 'Imports',
  58: 'Bean Imports',
  75: 'Roast & Ground Imports',
  82: 'Soluble Imports',
  86: 'Total Supply',
  88: 'Exports',
  90: 'Bean Exports',
  107: 'Roast & Ground Exports',
  114: 'Soluble Exports',
  125: 'Domestic Consumption',
  141: 'Rst,Ground Dom. Consum',
  154: 'Soluble Dom. Cons.',
  176: 'Ending Stocks',
  178: 'Total Distribution'
};

function round(value, decimals = 4) {
  if (value === null || value === undefined || Number.isNaN(value)) return null;
  return Number(Number(value).toFixed(decimals));
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const numeric = Number(value);
  return Number.isNaN(numeric) ? null : numeric;
}

function safeDivide(numerator, denominator, decimals = 4) {
  if (numerator === null || denominator === null || denominator === 0) return null;
  return round(numerator / denominator, decimals);
}

function pctChange(current, previous, decimals = 4) {
  if (current === null || previous === null || previous === 0) return null;
  return round(((current - previous) / previous) * 100, decimals);
}

function ppChange(current, previous, decimals = 4) {
  if (current === null || previous === null) return null;
  return round(current - previous, decimals);
}

function marketYearLabel(year) {
  return `${year}/${String((year + 1) % 100).padStart(2, '0')}`;
}

function formatMetric(value, decimals = 4) {
  return value === null ? 'n/a' : value.toFixed(decimals);
}

function buildYearRecord(yearEntry) {
  const attributesMt = yearEntry.attributes_mt;
  const attributesRaw = yearEntry.attributes_raw;

  const productionTotalMt = attributesMt['Production'] ?? null;
  const arabicaProductionMt = attributesMt['Arabica Production'] ?? null;
  const robustaProductionMt = attributesMt['Robusta Production'] ?? null;
  const otherProductionMt = attributesMt['Other Production'] ?? null;
  const exportsTotalMt = attributesMt['Exports'] ?? null;
  const beanExportsMt = attributesMt['Bean Exports'] ?? null;
  const roastGroundExportsMt = attributesMt['Roast & Ground Exports'] ?? null;
  const solubleExportsMt = attributesMt['Soluble Exports'] ?? null;
  const domesticConsumptionMt = attributesMt['Domestic Consumption'] ?? null;
  const consRoastGroundMt = attributesMt['Rst,Ground Dom. Consum'] ?? null;
  const consSolubleMt = attributesMt['Soluble Dom. Cons.'] ?? null;
  const beginningStocksMt = attributesMt['Beginning Stocks'] ?? null;
  const endingStocksMt = attributesMt['Ending Stocks'] ?? null;

  const arabicaSharePct = safeDivide(arabicaProductionMt, productionTotalMt, 6);
  const robustaSharePct = safeDivide(robustaProductionMt, productionTotalMt, 6);
  const valueAddedExportsMt = (roastGroundExportsMt ?? 0) + (solubleExportsMt ?? 0);
  const valueAddedExportsSharePct = exportsTotalMt !== null && exportsTotalMt !== 0
    ? round((valueAddedExportsMt / exportsTotalMt) * 100, 4)
    : null;
  const apparentTotalUseMt = exportsTotalMt !== null && domesticConsumptionMt !== null
    ? round(exportsTotalMt + domesticConsumptionMt, 4)
    : null;
  const exportToProductionRatio = safeDivide(exportsTotalMt, productionTotalMt, 6);
  const stockToUseRatio = safeDivide(endingStocksMt, apparentTotalUseMt, 6);
  const stockBalanceMt = beginningStocksMt !== null && endingStocksMt !== null
    ? round(endingStocksMt - beginningStocksMt, 4)
    : null;

  return {
    market_year: yearEntry.market_year,
    market_year_label: marketYearLabel(yearEntry.market_year),
    calendar_year: yearEntry.calendar_year,
    release_month: yearEntry.release_month,
    production_total_mt: productionTotalMt,
    arabica_production_mt: arabicaProductionMt,
    robusta_production_mt: robustaProductionMt,
    other_production_mt: otherProductionMt,
    exports_total_mt: exportsTotalMt,
    bean_exports_mt: beanExportsMt,
    roast_ground_exports_mt: roastGroundExportsMt,
    soluble_exports_mt: solubleExportsMt,
    domestic_consumption_mt: domesticConsumptionMt,
    cons_roast_ground_mt: consRoastGroundMt,
    cons_soluble_mt: consSolubleMt,
    beginning_stocks_mt: beginningStocksMt,
    ending_stocks_mt: endingStocksMt,
    arabica_share_pct: arabicaSharePct !== null ? round(arabicaSharePct * 100, 4) : null,
    robusta_share_pct: robustaSharePct !== null ? round(robustaSharePct * 100, 4) : null,
    value_added_exports_share_pct: valueAddedExportsSharePct,
    apparent_total_use_mt: apparentTotalUseMt,
    export_to_production_ratio: exportToProductionRatio,
    stock_to_use_ratio: stockToUseRatio,
    stock_balance_mt: stockBalanceMt,
    raw_attributes_1000_60kg_bags: attributesRaw
  };
}

// ── Normalizza tutte le righe API ─────────────────────────────────────────────

const rawRows = [];
for (const item of $input.all()) {
  if (Array.isArray(item.json)) {
    rawRows.push(...item.json);
  } else if (Array.isArray(item.json.data)) {
    rawRows.push(...item.json.data);
  } else if (Array.isArray(item.json.body)) {
    rawRows.push(...item.json.body);
  } else if (item.json && typeof item.json === 'object' && Object.prototype.hasOwnProperty.call(item.json, 'attributeId')) {
    rawRows.push(item.json);
  }
}

const normalizedRows = rawRows
  .map((row) => {
    const attributeId = toNumber(row.attributeId);
    const marketYear = toNumber(row.marketYear);
    const calendarYear = toNumber(row.calendarYear);
    const month = toNumber(row.month);
    const rawValue = toNumber(row.value);
    if (attributeId === null || marketYear === null || month === null || rawValue === null) return null;
    return {
      attribute_id: attributeId,
      attribute_name: ATTRIBUTE_MAP[attributeId] || `attribute_${attributeId}`,
      market_year: marketYear,
      calendar_year: calendarYear,
      month,
      raw_value_1000_60kg_bags: round(rawValue, 4),
      value_mt: round(rawValue * BAG_TO_MT, 4)
    };
  })
  .filter((row) => row !== null)
  .sort((a, b) => {
    if (a.market_year !== b.market_year) return a.market_year - b.market_year;
    if (a.month !== b.month) return a.month - b.month;
    return a.attribute_id - b.attribute_id;
  });

if (!normalizedRows.length) {
  throw new Error('USDA FAS PSD returned no valid rows for the requested market years');
}

// ── yearly_series: un record per anno (stima del mese più recente) ────────────

const yearMap = new Map();
for (const row of normalizedRows) {
  const yearEntry = yearMap.get(row.market_year) || {
    market_year: row.market_year,
    calendar_year: row.calendar_year,
    release_month: row.month,
    attributes_raw: {},
    attributes_mt: {}
  };
  yearEntry.calendar_year = row.calendar_year;
  // sovrascrive sempre → alla fine contiene il mese più recente (array già ordinato per month asc)
  yearEntry.release_month = row.month;
  yearEntry.attributes_raw[row.attribute_name] = row.raw_value_1000_60kg_bags;
  yearEntry.attributes_mt[row.attribute_name] = row.value_mt;
  yearMap.set(row.market_year, yearEntry);
}

const yearRecords = Array.from(yearMap.values())
  .map(buildYearRecord)
  .filter((row) => row.production_total_mt !== null)
  .sort((a, b) => a.market_year - b.market_year);

if (!yearRecords.length) {
  throw new Error('USDA FAS PSD produced no market-year records with production data');
}

const yearly_series = yearRecords.slice(-10).map((row) => ({
  market_year: row.market_year,
  market_year_label: row.market_year_label,
  release_month: row.release_month,
  production_total_mt: row.production_total_mt,
  arabica_production_mt: row.arabica_production_mt,
  robusta_production_mt: row.robusta_production_mt,
  exports_total_mt: row.exports_total_mt,
  domestic_consumption_mt: row.domestic_consumption_mt,
  ending_stocks_mt: row.ending_stocks_mt,
  stock_to_use_ratio: row.stock_to_use_ratio
}));

// ── monthly_series: ultimi 12 report mensili USDA ────────────────────────────
// Chiave = data di rilascio (calendar_year + month), non marketing year
// Per ogni rilascio prende le stime del marketing year più recente presente

const releaseDateMap = new Map();
for (const row of normalizedRows) {
  const releaseKey = `${row.calendar_year}-${String(row.month).padStart(2, '0')}`;
  if (!releaseDateMap.has(releaseKey)) {
    releaseDateMap.set(releaseKey, {
      calendar_year: row.calendar_year,
      release_month: row.month,
      release_year_month: releaseKey,
      market_years: new Map()
    });
  }
  const releaseEntry = releaseDateMap.get(releaseKey);
  if (!releaseEntry.market_years.has(row.market_year)) {
    releaseEntry.market_years.set(row.market_year, { attributes_mt: {} });
  }
  releaseEntry.market_years.get(row.market_year).attributes_mt[row.attribute_name] = row.value_mt;
}

const monthly_series = Array.from(releaseDateMap.values())
  .filter((entry) => entry.calendar_year >= currentYear - 1)
  .sort((a, b) => {
    if (a.calendar_year !== b.calendar_year) return a.calendar_year - b.calendar_year;
    return a.release_month - b.release_month;
  })
  .slice(-12)
  .map((entry) => {
    const latestMarketYear = Math.max(...Array.from(entry.market_years.keys()));
    const attrs = entry.market_years.get(latestMarketYear).attributes_mt;
    const exportsTotal = attrs['Exports'] ?? null;
    const domCons = attrs['Domestic Consumption'] ?? null;
    const endStocks = attrs['Ending Stocks'] ?? null;
    const totalUse = (exportsTotal !== null && domCons !== null) ? round(exportsTotal + domCons, 4) : null;
    return {
      release_year_month: entry.release_year_month,
      market_year: latestMarketYear,
      market_year_label: marketYearLabel(latestMarketYear),
      production_total_mt: attrs['Production'] ?? null,
      arabica_production_mt: attrs['Arabica Production'] ?? null,
      robusta_production_mt: attrs['Robusta Production'] ?? null,
      exports_total_mt: exportsTotal,
      domestic_consumption_mt: domCons,
      ending_stocks_mt: endStocks,
      stock_to_use_ratio: safeDivide(endStocks, totalUse, 6)
    };
  });

// ── latest / previous / derived metrics ──────────────────────────────────────

const latest = { ...yearRecords[yearRecords.length - 1] };
const previous = yearRecords.length > 1 ? { ...yearRecords[yearRecords.length - 2] } : null;

const productionYoYPct = previous ? pctChange(latest.production_total_mt, previous.production_total_mt) : null;
const exportsYoYPct = previous ? pctChange(latest.exports_total_mt, previous.exports_total_mt) : null;
const domesticConsumptionYoYPct = previous ? pctChange(latest.domestic_consumption_mt, previous.domestic_consumption_mt) : null;
const endingStocksYoYPct = previous ? pctChange(latest.ending_stocks_mt, previous.ending_stocks_mt) : null;
const arabicaShareChangePp = previous ? ppChange(latest.arabica_share_pct, previous.arabica_share_pct) : null;
const robustaShareChangePp = previous ? ppChange(latest.robusta_share_pct, previous.robusta_share_pct) : null;

const signals = [];
if (productionYoYPct !== null && productionYoYPct >= 5) signals.push('production_up');
if (productionYoYPct !== null && productionYoYPct <= -5) signals.push('production_down');
if (productionYoYPct !== null && productionYoYPct <= -10) signals.push('production_down_sharp');
if (previous && latest.arabica_production_mt !== null && previous.arabica_production_mt !== null && pctChange(latest.arabica_production_mt, previous.arabica_production_mt) <= -5) signals.push('arabica_down');
if (robustaShareChangePp !== null && robustaShareChangePp >= 2) signals.push('robusta_share_rising');
if (robustaShareChangePp !== null && robustaShareChangePp <= -2) signals.push('robusta_share_falling');
if (exportsYoYPct !== null && exportsYoYPct >= 5) signals.push('exports_accelerating');
if (latest.export_to_production_ratio !== null && latest.export_to_production_ratio >= 0.70) signals.push('exports_pressure_high');
if (domesticConsumptionYoYPct !== null && domesticConsumptionYoYPct >= 3) signals.push('domestic_absorption_rising');
if (endingStocksYoYPct !== null && endingStocksYoYPct <= -10) signals.push('ending_stocks_drawdown');
if (endingStocksYoYPct !== null && endingStocksYoYPct >= 10) signals.push('ending_stocks_build');
if (latest.stock_to_use_ratio !== null && latest.stock_to_use_ratio <= 0.15) signals.push('stock_buffer_tight');
if (latest.stock_to_use_ratio !== null && latest.stock_to_use_ratio >= 0.25) signals.push('stock_buffer_healthy');
if (productionYoYPct !== null && exportsYoYPct !== null && endingStocksYoYPct !== null && productionYoYPct <= 0 && exportsYoYPct > 0 && endingStocksYoYPct < 0) signals.push('balance_tightening');

const tighteningScore = [
  productionYoYPct !== null && productionYoYPct <= -5,
  endingStocksYoYPct !== null && endingStocksYoYPct <= -10,
  latest.stock_to_use_ratio !== null && latest.stock_to_use_ratio <= 0.15,
  latest.export_to_production_ratio !== null && latest.export_to_production_ratio >= 0.70
].filter(Boolean).length;

const expansionScore = [
  productionYoYPct !== null && productionYoYPct >= 5,
  endingStocksYoYPct !== null && endingStocksYoYPct >= 10,
  latest.stock_to_use_ratio !== null && latest.stock_to_use_ratio >= 0.25
].filter(Boolean).length;

let movementLabel = 'mixed';
if (tighteningScore >= 2) movementLabel = 'supply_tightening';
else if (expansionScore >= 2) movementLabel = 'supply_expanding';

let summaryEn = `Latest USDA PSD Brazil coffee snapshot for market year ${latest.market_year_label} reports ${formatMetric(latest.production_total_mt)} million metric tons of production, ${formatMetric(latest.exports_total_mt)} million metric tons of exports, and ${formatMetric(latest.ending_stocks_mt)} million metric tons of ending stocks.`;
if (previous) {
  summaryEn += ` Versus ${previous.market_year_label}, production changed by ${formatMetric(productionYoYPct, 4)}%, exports by ${formatMetric(exportsYoYPct, 4)}%, and ending stocks by ${formatMetric(endingStocksYoYPct, 4)}%.`;
}
if (movementLabel === 'supply_tightening') summaryEn += ' The balance points to tighter supply conditions.';
if (movementLabel === 'supply_expanding') summaryEn += ' The balance points to looser supply conditions.';
if (movementLabel === 'mixed') summaryEn += ' Signals are mixed across supply, exports, and stocks.';

return [{
  json: {
    source: 'USDA_FAS_PSD',
    source_format: 'json_api',
    source_url_template: 'https://api.fas.usda.gov/api/psd/commodity/0711100/country/BR/year/{marketYear}',
    source_url: 'https://api.fas.usda.gov/api/psd/commodity/0711100/country/BR/year/{marketYear}',
    country: 'BR',
    macroarea: 'colture',
    commodity_code: '0711100',
    commodity_name: 'Coffee, Green',
    marketing_year_basis: 'July-June',
    collected_at: now,
    collected_period: _collectedPeriod,
        dataset: 'PSD',
    lookback_years_requested: lookbackYears,
    requested_years: Array.from({ length: lookbackYears }, (_, index) => startYear + index),
    total_records_fetched: normalizedRows.length,
    market_year: latest.market_year,
    market_year_label: latest.market_year_label,
    calendar_year: latest.calendar_year,
    release_month: latest.release_month,
    units: {
      raw: '1000_60kg_bags',
      normalized: 'million_metric_tons'
    },
    latest: {
      production_total_mt: latest.production_total_mt,
      arabica_production_mt: latest.arabica_production_mt,
      robusta_production_mt: latest.robusta_production_mt,
      other_production_mt: latest.other_production_mt,
      exports_total_mt: latest.exports_total_mt,
      bean_exports_mt: latest.bean_exports_mt,
      roast_ground_exports_mt: latest.roast_ground_exports_mt,
      soluble_exports_mt: latest.soluble_exports_mt,
      domestic_consumption_mt: latest.domestic_consumption_mt,
      cons_roast_ground_mt: latest.cons_roast_ground_mt,
      cons_soluble_mt: latest.cons_soluble_mt,
      beginning_stocks_mt: latest.beginning_stocks_mt,
      ending_stocks_mt: latest.ending_stocks_mt
    },
    previous: previous ? {
      market_year: previous.market_year,
      market_year_label: previous.market_year_label,
      release_month: previous.release_month,
      production_total_mt: previous.production_total_mt,
      exports_total_mt: previous.exports_total_mt,
      domestic_consumption_mt: previous.domestic_consumption_mt,
      ending_stocks_mt: previous.ending_stocks_mt
    } : null,
    derived_metrics: {
      arabica_share_pct: latest.arabica_share_pct,
      robusta_share_pct: latest.robusta_share_pct,
      value_added_exports_share_pct: latest.value_added_exports_share_pct,
      apparent_total_use_mt: latest.apparent_total_use_mt,
      export_to_production_ratio: latest.export_to_production_ratio,
      stock_to_use_ratio: latest.stock_to_use_ratio,
      stock_balance_mt: latest.stock_balance_mt,
      production_yoy_pct: productionYoYPct,
      exports_yoy_pct: exportsYoYPct,
      domestic_consumption_yoy_pct: domesticConsumptionYoYPct,
      ending_stocks_yoy_pct: endingStocksYoYPct,
      arabica_share_change_pp: arabicaShareChangePp,
      robusta_share_change_pp: robustaShareChangePp
    },
    movement_label: movementLabel,
    signals: Array.from(new Set(signals)),
    summary_en: summaryEn,
    yearly_series: yearly_series,
    monthly_series: monthly_series,
    raw_latest_attributes: latest.raw_attributes_1000_60kg_bags,
    _chart_fields: ["yearly_series", "monthly_series", "raw_latest_attributes"]
  }
}];

const now = new Date().toISOString();
const meta = $('USDA Parse Signals').item.json;

return [{
  json: {
    source: 'USDA_FAS_PSD',
    country: 'BR',
    macroarea: 'colture',
    cadenza: 'weekly',
    run_date: now,
    status: 'done',
    completed_at: now,
    market_year: meta.market_year_label || null,
  },
}];

const raw = ($json.text || '').trim();
const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();
const parsed = JSON.parse(cleaned);
const base = $('USDA Parse PSD').item.json;

return [{
  json: {
    ...base,
    rule_based_signals: Array.isArray(base.signals) ? base.signals : [],
    rule_based_movement_label: base.movement_label || 'mixed',
    fallback_summary_en: base.summary_en || '',
    movement_label: parsed.movement_label || base.movement_label || 'mixed',
signals: Array.isArray(parsed.signals) ? parsed.signals : (Array.isArray(base.signals) ? base.signals : []),
    summary_en: parsed.summary_en || base.summary_en || ''
  }
}];

const items = $input.all();
const first = items[0];
const err = first?.json?.error ?? first?.error?.message ?? '';
const statusCode = first?.json?.statusCode ?? first?.json?.status ?? 0;
if (err || statusCode >= 400) {
  return [{ json: {
    _api_skip: true,
    source: '05_USDA_FAS_PSD',
    country: 'BR',
    status: 'skipped_api_error',
    reason: `API unavailable: ${err || 'HTTP ' + statusCode}`,
    run_date: new Date().toISOString(),
    completed_at: new Date().toISOString()
  } }];
}
return items.map(item => ({ json: item.json }));
